def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    n = len(bins)
    base_weight = 1.0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0.0
        for power in range(1, 21):
            if power % 5 == 0:
                multiplier = np.sin(power * ratio * np.pi)
            elif power % 3 == 0:
                multiplier = np.cos(power * ratio)
            else:
                multiplier = np.tanh(ratio * power)
            sign = (-1) ** power
            term = sign * multiplier / (power ** 1.5)
            score += term
        if ratio == 1:
            score = 0.0
        elif ratio > 0.75:
            score *= 0.7
        elif ratio > 0.5:
            score *= 1.2
        else:
            score *= 1.5
        adjustment = 1.0
        if capacity < item * 1.2:
            adjustment *= 2.5
        elif capacity < item * 1.8:
            adjustment *= 1.8
        elif capacity < item * 2.5:
            adjustment *= 1.3
        else:
            adjustment *= 1.0
        neighborhood_penalty = 0.0
        for offset in range(-4, 5):
            if offset == 0:
                continue
            neighbor_idx = i + offset
            if 0 <= neighbor_idx < n:
                neighbor_cap = bins[neighbor_idx]
                if neighbor_cap > 0:
                    overlap = item / neighbor_cap
                    if 0 < overlap < 1:
                        weight = 1 / (abs(offset) + 1)
                        neighborhood_penalty += weight * (1 - overlap) ** 3
        penalty_norm = neighborhood_penalty / 8.0
        score = abs(score) * adjustment + penalty_norm
        if i % 2 == 0:
            score *= 0.95
        if i % 7 == 3:
            score -= 0.05
        if score < 0:
            score = 0.0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return np.full_like(bins, np.inf, dtype=float)
    min_priority = np.min(finite_priorities)
    max_priority = np.max(finite_priorities)
    range_priority = max_priority - min_priority if max_priority != min_priority else 1.0
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 10
        else:
            normalized = (priorities[i] - min_priority) / range_priority
            if normalized < 0.3:
                priorities[i] *= 0.8
            elif normalized > 0.7:
                priorities[i] *= 1.1
    return priorities
